std::string jsonEscape(const std::string &value) {
  std::ostringstream out;
  for (char c : value) {
    switch (c) {
      case '\\': out << "\\\\"; break;
      case '"': out << "\\\""; break;
      case '\n': out << "\\n"; break;
      case '\r': out << "\\r"; break;
      case '\t': out << "\\t"; break;
      default: out << c; break;
    }
  }
  return out.str();
}

std::string jsonStringArray(const std::vector<std::string> &values) {
  std::ostringstream json;
  json << "[";
  for (size_t i = 0; i < values.size(); i++) {
    if (i > 0) json << ",";
    json << "\"" << jsonEscape(values[i]) << "\"";
  }
  json << "]";
  return json.str();
}

uint8_t clampByte(int value) {
  if (value < 0) return 0;
  if (value > 255) return 255;
  return static_cast<uint8_t>(value);
}

NativeColor colorFromJson(JsonArray array, NativeColor fallback) {
  if (array.isNull() || array.size() < 3) return fallback;
  fallback.r = clampByte(array[0] | fallback.r);
  fallback.g = clampByte(array[1] | fallback.g);
  fallback.b = clampByte(array[2] | fallback.b);
  if (array.size() > 3) fallback.w = clampByte(array[3] | fallback.w);
  return fallback;
}

void addColorJson(std::ostringstream &json, const NativeColor &color) {
  json << "[" << static_cast<int>(color.r)
       << "," << static_cast<int>(color.g)
       << "," << static_cast<int>(color.b)
       << "," << static_cast<int>(color.w) << "]";
}

NativeColor scaleColor(NativeColor color, uint8_t amount) {
  color.r = static_cast<uint8_t>((static_cast<uint16_t>(color.r) * amount) / 255);
  color.g = static_cast<uint8_t>((static_cast<uint16_t>(color.g) * amount) / 255);
  color.b = static_cast<uint8_t>((static_cast<uint16_t>(color.b) * amount) / 255);
  color.w = static_cast<uint8_t>((static_cast<uint16_t>(color.w) * amount) / 255);
  return color;
}

NativeColor blend(NativeColor a, NativeColor b, uint8_t amount) {
  const uint16_t inverse = 255 - amount;
  return NativeColor{
    static_cast<uint8_t>((a.r * inverse + b.r * amount) / 255),
    static_cast<uint8_t>((a.g * inverse + b.g * amount) / 255),
    static_cast<uint8_t>((a.b * inverse + b.b * amount) / 255),
    static_cast<uint8_t>((a.w * inverse + b.w * amount) / 255),
    0
  };
}

NativeColor hsv(uint16_t hue, uint8_t sat, uint8_t val) {
  const uint8_t region = (hue / 43) % 6;
  const uint8_t remainder = static_cast<uint8_t>((hue - (region * 43)) * 6);
  const uint8_t p = static_cast<uint8_t>((static_cast<uint16_t>(val) * (255 - sat)) >> 8);
  const uint8_t q = static_cast<uint8_t>((static_cast<uint16_t>(val) * (255 - ((static_cast<uint16_t>(sat) * remainder) >> 8))) >> 8);
  const uint8_t t = static_cast<uint8_t>((static_cast<uint16_t>(val) * (255 - ((static_cast<uint16_t>(sat) * (255 - remainder)) >> 8))) >> 8);

  switch (region) {
    case 0: return NativeColor{val, t, p, 0, 0};
    case 1: return NativeColor{q, val, p, 0, 0};
    case 2: return NativeColor{p, val, t, 0, 0};
    case 3: return NativeColor{p, q, val, 0, 0};
    case 4: return NativeColor{t, p, val, 0, 0};
    default: return NativeColor{val, p, q, 0, 0};
  }
}

NativeColor paletteColor(uint8_t palette, uint16_t index, const NativeSegmentState &segment) {
  switch (palette) {
    case 2: return segment.colors[0];
    case 3: return blend(segment.colors[0], NativeColor{255, 255, 255, 0, 0}, index & 0xFF);
    case 4: return blend(segment.colors[0], segment.colors[1], index & 0xFF);
    case 8: return blend(NativeColor{255, 80, 0, 0, 0}, NativeColor{120, 0, 0, 0, 0}, index & 0xFF);
    case 9: return blend(NativeColor{0, 32, 180, 0, 0}, NativeColor{0, 220, 255, 0, 0}, index & 0xFF);
    case 10: return blend(NativeColor{0, 120, 0, 0, 0}, NativeColor{160, 255, 80, 0, 0}, index & 0xFF);
    case 11:
    case 12: return hsv(index, 255, 255);
    case 16: return (index & 0x80) ? NativeColor{0, 0, 255, 0, 0} : NativeColor{255, 0, 0, 0, 0};
    default: return blend(segment.colors[0], hsv(index, 255, 255), palette == 0 ? 0 : 96);
  }
}

uint32_t stableNoise(uint32_t value) {
  value ^= value >> 16;
  value *= 0x7feb352dU;
  value ^= value >> 15;
  value *= 0x846ca68bU;
  value ^= value >> 16;
  return value;
}

void renderSegmentEffect(const NativeCoreState &state, const NativeSegmentState &segment, NativeRenderBuffer &buffer, uint64_t nowMs) {
  if (!state.on || !segment.on || state.bri == 0 || segment.bri == 0) return;

  const uint16_t start = std::min<uint16_t>(segment.start, buffer.length());
  const uint16_t stop = std::min<uint16_t>(segment.stop, buffer.length());
  if (stop <= start) return;

  const uint16_t length = stop - start;
  const uint16_t phase = static_cast<uint16_t>((nowMs / std::max<uint8_t>(1, 256 - segment.sx)) & 0xFFFF);
  const uint8_t totalBrightness = static_cast<uint8_t>((static_cast<uint16_t>(state.bri) * segment.bri) / 255);

  for (uint16_t offset = 0; offset < length; offset++) {
    NativeColor color = segment.colors[0];
    const uint16_t wheel = static_cast<uint16_t>((offset * 256U / std::max<uint16_t>(1, length)) + phase);

    switch (segment.fx) {
      case 0: // Solid
        color = segment.colors[0];
        break;
      case 1: // Blink
      case 23: // Strobe
        color = ((nowMs / std::max<uint16_t>(80, 600 - segment.sx * 2)) & 1) ? segment.colors[0] : segment.colors[1];
        break;
      case 2: // Breathe
      case 12: { // Fade
        const double radians = static_cast<double>(phase % 1024) * 6.283185307179586 / 1024.0;
        color = scaleColor(segment.colors[0], static_cast<uint8_t>(24 + (std::sin(radians) + 1.0) * 115.0));
        break;
      }
      case 8: // Colorloop
      case 9: // Rainbow
      case 14:
      case 30:
        color = hsv(wheel, 255, 255);
        break;
      case 13: // Theater
      case 28: // Chase
        color = (((offset + phase / 8) % 6) < 2) ? segment.colors[0] : segment.colors[1];
        break;
      case 20: // Sparkle
      case 87:
      case 103: {
        const uint32_t noise = stableNoise(static_cast<uint32_t>(offset) + static_cast<uint32_t>(nowMs / 80));
        color = (noise % 100) < std::max<uint8_t>(4, segment.ix / 8) ? NativeColor{255, 255, 255, 0, 0} : segment.colors[0];
        break;
      }
      case 46: // Gradient
      case 65: // Palette
        color = paletteColor(segment.pal, wheel, segment);
        break;
      case 76: { // Meteor
        const uint16_t head = static_cast<uint16_t>((phase / 2) % length);
        const uint16_t distance = (offset > head) ? offset - head : head - offset;
        color = scaleColor(segment.colors[0], distance < 8 ? static_cast<uint8_t>(255 - distance * 28) : 0);
        break;
      }
      case 92:
      case 93:
      case 94: { // Sinelon family
        const double radians = static_cast<double>(phase % 1024) * 6.283185307179586 / 1024.0;
        const uint16_t center = static_cast<uint16_t>((std::sin(radians) + 1.0) * 0.5 * (length - 1));
        const uint16_t distance = (offset > center) ? offset - center : center - offset;
        color = distance < 6 ? scaleColor(paletteColor(segment.pal, wheel, segment), static_cast<uint8_t>(255 - distance * 38)) : NativeColor{};
        break;
      }
      default:
        color = paletteColor(segment.pal, static_cast<uint16_t>(wheel + segment.fx * 19), segment);
        if (((segment.fx >= 112 && segment.fx <= 143) || segment.fx >= 146) && segment.ix == 0) {
          color = scaleColor(color, 160); // Audioreactive fallback when no microphone data exists.
        }
        break;
    }

    buffer.setPixel(start + offset, scaleColor(color, totalBrightness));
  }
}

