NativeWledCore::NativeWledCore(std::filesystem::path configRoot) : _configRoot(std::move(configRoot)) {
}

void NativeWledCore::begin(size_t ledCount, uint64_t nowMs) {
  std::lock_guard<std::mutex> lock(_mutex);
  _startedMs = nowMs;
  ensureDefaults(ledCount);
  ensurePresetsFile();
}

void NativeWledCore::ensureDefaults(size_t ledCount) {
  if (_state.segments.empty()) {
    NativeSegmentState segment;
    segment.stop = static_cast<uint16_t>(std::min<size_t>(ledCount, UINT16_MAX));
    _state.segments.push_back(segment);
  } else {
    _state.segments[0].start = 0;
    _state.segments[0].stop = static_cast<uint16_t>(std::min<size_t>(ledCount, UINT16_MAX));
  }
}

void NativeWledCore::ensurePresetsFile() const {
  if (_configRoot.empty()) return;
  std::error_code error;
  std::filesystem::create_directories(_configRoot, error);
  const std::filesystem::path presets = _configRoot / "presets.json";
  if (std::filesystem::exists(presets, error)) return;
  std::ofstream file(presets);
  file << "{\"0\":{}}\n";
}

void NativeWledCore::tick(uint64_t nowMs) {
  std::lock_guard<std::mutex> lock(_mutex);
  if (_state.nightlight.active && _state.nightlight.durationMinutes > 0) {
    const uint64_t durationMs = static_cast<uint64_t>(_state.nightlight.durationMinutes) * 60000ULL;
    if (nowMs - _state.nightlight.startedMs >= durationMs) {
      _state.bri = _state.nightlight.targetBri;
      if (_state.bri == 0) _state.on = false;
      _state.nightlight.active = false;
    }
  }

  if (_playlist.active && !_playlist.entries.empty()) {
    const PlaylistEntry &entry = _playlist.entries[_playlist.index];
    if (nowMs - _playlist.entryStartedMs >= entry.durationMs) advancePlaylistLocked(nowMs);
  }
}

void NativeWledCore::render(NativeRenderBuffer &buffer, uint64_t nowMs) {
  std::lock_guard<std::mutex> lock(_mutex);
  buffer.clear();
  NativeCoreState effective = _state;
  effective.bri = effectiveBrightness(nowMs);
  for (const NativeSegmentState &segment : effective.segments) renderSegmentEffect(effective, segment, buffer, nowMs);
}

void NativeWledCore::applyJsonState(const std::string &json, uint64_t nowMs) {
  std::lock_guard<std::mutex> lock(_mutex);
  applyJsonStateLocked(json, nowMs, false);
}

void NativeWledCore::applyJsonStateLocked(const std::string &json, uint64_t nowMs, bool fromPreset) {
  DynamicJsonDocument doc(12288);
  if (deserializeJson(doc, json) != DeserializationError::Ok) return;
  JsonObject root = doc.as<JsonObject>();

  if (!fromPreset && root["psave"].is<int>()) {
    savePreset(static_cast<uint8_t>(root["psave"] | 0));
  }

  if (!fromPreset && root["ps"].is<int>()) {
    _playlist.active = false;
    applyPresetJson(static_cast<uint8_t>(root["ps"] | 0), presetObjectJson(static_cast<uint8_t>(root["ps"] | 0)), nowMs);
    return;
  }

  if (root["on"].is<bool>()) _state.on = root["on"].as<bool>();
  if (root["bri"].is<int>()) _state.bri = clampByte(root["bri"].as<int>());
  if (root["transition"].is<int>()) _state.transitionMs = static_cast<uint16_t>(std::max(0, root["transition"].as<int>()) * 100);
  if (root["np"].as<bool>()) advancePlaylistLocked(nowMs);

  JsonObject nl = root["nl"];
  if (!nl.isNull()) {
    if (nl["dur"].is<int>()) _state.nightlight.durationMinutes = static_cast<uint16_t>(std::max(0, nl["dur"].as<int>()));
    if (nl["mode"].is<int>()) _state.nightlight.mode = clampByte(nl["mode"].as<int>());
    if (nl["tbri"].is<int>()) _state.nightlight.targetBri = clampByte(nl["tbri"].as<int>());
    if (nl["on"].is<bool>()) {
      _state.nightlight.active = nl["on"].as<bool>();
      if (_state.nightlight.active) _state.nightlight.startedMs = nowMs;
    }
  }

  JsonArray segments = root["seg"];
  if (!segments.isNull()) {
    for (JsonObject incoming : segments) {
      const size_t index = incoming["id"] | 0;
      if (index >= _state.segments.size()) _state.segments.resize(index + 1);
      NativeSegmentState &segment = _state.segments[index];
      segment.id = static_cast<uint16_t>(index);
      if (incoming["start"].is<int>()) segment.start = static_cast<uint16_t>(std::max(0, incoming["start"].as<int>()));
      if (incoming["stop"].is<int>()) segment.stop = static_cast<uint16_t>(std::max(0, incoming["stop"].as<int>()));
      if (incoming["len"].is<int>()) segment.stop = static_cast<uint16_t>(segment.start + std::max(0, incoming["len"].as<int>()));
      if (incoming["on"].is<bool>()) segment.on = incoming["on"].as<bool>();
      if (incoming["bri"].is<int>()) segment.bri = clampByte(incoming["bri"].as<int>());
      if (incoming["fx"].is<int>()) segment.fx = clampByte(incoming["fx"].as<int>());
      if (incoming["sx"].is<int>()) segment.sx = clampByte(incoming["sx"].as<int>());
      if (incoming["ix"].is<int>()) segment.ix = clampByte(incoming["ix"].as<int>());
      if (incoming["pal"].is<int>()) segment.pal = clampByte(incoming["pal"].as<int>());
      JsonArray colors = incoming["col"];
      for (size_t i = 0; i < 3 && !colors.isNull() && i < colors.size(); i++) {
        segment.colors[i] = colorFromJson(colors[i], segment.colors[i]);
      }
    }
  }

  if (!root["playlist"].isNull()) loadPlaylistFromJsonLocked(0, json, nowMs);
  if (fromPreset) _state.currentPreset = root["n"].isNull() ? _state.currentPreset : _state.currentPreset;
}

std::string NativeWledCore::presetObjectJson(uint8_t presetId) const {
  if (_configRoot.empty() || presetId == 0) return "";
  std::ifstream file(_configRoot / "presets.json");
  if (!file) return "";
  std::ostringstream contents;
  contents << file.rdbuf();

  DynamicJsonDocument doc(65536);
  if (deserializeJson(doc, contents.str()) != DeserializationError::Ok) return "";
  JsonVariant preset = doc[String(presetId).c_str()];
  if (preset.isNull()) return "";
  std::string json;
  serializeJson(preset, json);
  return json;
}

bool NativeWledCore::applyPresetJson(uint8_t presetId, const std::string &json, uint64_t nowMs) {
  if (json.empty()) return false;
  _state.currentPreset = presetId;
  applyJsonStateLocked(json, nowMs, true);
  return true;
}

bool NativeWledCore::applyPreset(uint8_t presetId, uint64_t nowMs) {
  std::lock_guard<std::mutex> lock(_mutex);
  _playlist.active = false;
  return applyPresetJson(presetId, presetObjectJson(presetId), nowMs);
}

bool NativeWledCore::savePreset(uint8_t presetId) {
  if (_configRoot.empty() || presetId == 0 || presetId > 250) return false;
  ensurePresetsFile();

  std::ifstream in(_configRoot / "presets.json");
  std::ostringstream contents;
  contents << in.rdbuf();

  DynamicJsonDocument doc(65536);
  if (deserializeJson(doc, contents.str()) != DeserializationError::Ok) doc.to<JsonObject>();
  JsonObject root = doc.as<JsonObject>();
  JsonObject preset = root.createNestedObject(String(presetId).c_str());
  preset["n"] = "Native preset";
  preset["on"] = _state.on;
  preset["bri"] = _state.bri;
  JsonArray segs = preset.createNestedArray("seg");
  for (const NativeSegmentState &segment : _state.segments) {
    JsonObject s = segs.createNestedObject();
    s["id"] = segment.id;
    s["start"] = segment.start;
    s["stop"] = segment.stop;
    s["fx"] = segment.fx;
    s["sx"] = segment.sx;
    s["ix"] = segment.ix;
    s["pal"] = segment.pal;
    JsonArray colors = s.createNestedArray("col");
    for (const NativeColor &color : segment.colors) {
      JsonArray c = colors.createNestedArray();
      c.add(color.r);
      c.add(color.g);
      c.add(color.b);
      c.add(color.w);
    }
  }

  std::ofstream out(_configRoot / "presets.json");
  if (!out) return false;
  serializeJson(doc, out);
  out << "\n";
  return true;
}

bool NativeWledCore::loadPlaylistFromJsonLocked(uint8_t presetId, const std::string &json, uint64_t nowMs) {
  DynamicJsonDocument doc(16384);
  if (deserializeJson(doc, json) != DeserializationError::Ok) return false;
  JsonObject playlist = doc["playlist"];
  if (playlist.isNull()) return false;

  JsonArray presets = playlist["ps"];
  if (presets.isNull() || presets.size() == 0) return false;

  PlaylistState next;
  next.active = true;
  next.presetId = presetId;
  next.repeatRemaining = static_cast<uint16_t>(std::max(0, playlist["repeat"] | 1));
  next.endPreset = playlist["end"] | 0;
  next.shuffle = playlist["r"] | false;
  next.entryStartedMs = nowMs;

  JsonArray durations = playlist["dur"];
  JsonArray transitions = playlist["transition"];
  for (size_t i = 0; i < presets.size() && i < 100; i++) {
    PlaylistEntry entry;
    entry.preset = presets[i] | 0;
    const int dur = durations.isNull() ? (playlist["dur"] | 100) : (durations[i] | 100);
    entry.durationMs = static_cast<uint32_t>(std::max(0, dur)) * 100UL;
    const int transition = transitions.isNull() ? (playlist["transition"] | 7) : (transitions[i] | 7);
    entry.transitionMs = static_cast<uint16_t>(std::max(0, transition) * 100);
    next.entries.push_back(entry);
  }

  _playlist = next;
  _state.currentPlaylist = presetId > 0 ? presetId : 0;
  applyPlaylistEntryLocked(nowMs);
  return true;
}

void NativeWledCore::applyPlaylistEntryLocked(uint64_t nowMs) {
  if (!_playlist.active || _playlist.entries.empty()) return;
  const PlaylistEntry &entry = _playlist.entries[_playlist.index];
  _state.transitionMs = entry.transitionMs;
  const std::string preset = presetObjectJson(entry.preset);
  if (!preset.empty()) applyPresetJson(entry.preset, preset, nowMs);
  _playlist.entryStartedMs = nowMs;
}

void NativeWledCore::advancePlaylist(uint64_t nowMs) {
  std::lock_guard<std::mutex> lock(_mutex);
  advancePlaylistLocked(nowMs);
}

void NativeWledCore::advancePlaylistLocked(uint64_t nowMs) {
  if (!_playlist.active || _playlist.entries.empty()) return;
  _playlist.index++;
  if (_playlist.index >= _playlist.entries.size()) {
    _playlist.index = 0;
    if (_playlist.repeatRemaining == 1) {
      const uint8_t endPreset = _playlist.endPreset;
      _playlist = PlaylistState{};
      _state.currentPlaylist = -1;
      if (endPreset > 0 && endPreset < 251) applyPresetJson(endPreset, presetObjectJson(endPreset), nowMs);
      return;
    }
    if (_playlist.repeatRemaining > 1) _playlist.repeatRemaining--;
    if (_playlist.shuffle && _playlist.entries.size() > 1) std::rotate(_playlist.entries.begin(), _playlist.entries.begin() + 1, _playlist.entries.end());
  }
  applyPlaylistEntryLocked(nowMs);
}

uint8_t NativeWledCore::effectiveBrightness(uint64_t nowMs) const {
  if (!_state.nightlight.active || _state.nightlight.durationMinutes == 0) return _state.bri;

  const uint64_t durationMs = static_cast<uint64_t>(_state.nightlight.durationMinutes) * 60000ULL;
  const uint64_t elapsed = std::min<uint64_t>(durationMs, nowMs - _state.nightlight.startedMs);
  const int start = _state.bri;
  const int target = _state.nightlight.targetBri;
  return clampByte(start + static_cast<int>((static_cast<int64_t>(target - start) * static_cast<int64_t>(elapsed)) / static_cast<int64_t>(durationMs)));
}

std::string NativeWledCore::jsonState(uint64_t nowMs) const {
  std::lock_guard<std::mutex> lock(_mutex);
  std::ostringstream json;
  json << "{\"on\":" << (_state.on ? "true" : "false")
       << ",\"bri\":" << static_cast<int>(effectiveBrightness(nowMs))
       << ",\"transition\":" << (_state.transitionMs / 100)
       << ",\"ps\":" << static_cast<int>(_state.currentPreset)
       << ",\"pl\":" << _state.currentPlaylist
       << ",\"nl\":{\"on\":" << (_state.nightlight.active ? "true" : "false")
       << ",\"dur\":" << _state.nightlight.durationMinutes
       << ",\"mode\":" << static_cast<int>(_state.nightlight.mode)
       << ",\"tbri\":" << static_cast<int>(_state.nightlight.targetBri)
       << ",\"rem\":";
  if (_state.nightlight.active) {
    const uint64_t durationMs = static_cast<uint64_t>(_state.nightlight.durationMinutes) * 60000ULL;
    const uint64_t elapsed = std::min<uint64_t>(durationMs, nowMs - _state.nightlight.startedMs);
    json << static_cast<int>((durationMs - elapsed) / 1000);
  } else {
    json << -1;
  }
  json << "},\"seg\":[";
  for (size_t i = 0; i < _state.segments.size(); i++) {
    const NativeSegmentState &segment = _state.segments[i];
    if (i > 0) json << ",";
    json << "{\"id\":" << segment.id
         << ",\"start\":" << segment.start
         << ",\"stop\":" << segment.stop
         << ",\"len\":" << (segment.stop > segment.start ? segment.stop - segment.start : 0)
         << ",\"on\":" << (segment.on ? "true" : "false")
         << ",\"bri\":" << static_cast<int>(segment.bri)
         << ",\"fx\":" << static_cast<int>(segment.fx)
         << ",\"sx\":" << static_cast<int>(segment.sx)
         << ",\"ix\":" << static_cast<int>(segment.ix)
         << ",\"pal\":" << static_cast<int>(segment.pal)
         << ",\"col\":[";
    for (size_t c = 0; c < 3; c++) {
      if (c > 0) json << ",";
      addColorJson(json, segment.colors[c]);
    }
    json << "]}";
  }
  json << "]}";
  return json.str();
}

std::string NativeWledCore::jsonInfo(const std::string &version, const std::string &nativeMac, const NativeRenderBuffer &buffer, uint64_t nowMs) const {
  std::lock_guard<std::mutex> lock(_mutex);
  std::ostringstream json;
  json << "{\"ver\":\"" << jsonEscape(version)
       << "\",\"vid\":1700000"
       << ",\"leds\":{\"count\":" << buffer.length()
       << ",\"rgbw\":true,\"wv\":true,\"pwr\":" << buffer.estimatedCurrentMilliamps() << "}"
       << ",\"fxcount\":" << effectNames().size()
       << ",\"palcount\":" << paletteNames().size()
       << ",\"cpalcount\":0,\"umpalcount\":0,\"cpalmax\":0"
       << ",\"name\":\"WLED Native\""
       << ",\"mac\":\"" << jsonEscape(nativeMac) << "\""
       << ",\"freeheap\":" << getFreeHeap()
       << ",\"uptime\":" << ((nowMs - _startedMs) / 1000)
       << ",\"time\":\"" << (nowMs / 1000) << "\""
       << "}";
  return json.str();
}

std::string NativeWledCore::jsonStateInfo(const std::string &version, const std::string &nativeMac, const NativeRenderBuffer &buffer, uint64_t nowMs) const {
  return "{\"state\":" + jsonState(nowMs) + ",\"info\":" + jsonInfo(version, nativeMac, buffer, nowMs) + "}";
}

std::string NativeWledCore::jsonEffects() const {
  return jsonStringArray(effectNames());
}

std::string NativeWledCore::jsonFxData() const {
  std::vector<std::string> data;
  data.reserve(effectNames().size());
  for (const std::string &name : effectNames()) data.push_back(name + "@!,!;!,!,!;!;01");
  return jsonStringArray(data);
}

std::string NativeWledCore::jsonPalettes() const {
  return jsonStringArray(paletteNames());
}

std::string NativeWledCore::jsonPaletteData() const {
  return "{\"m\":0,\"p\":{\"0\":[0,255,160,0,255,255,255],\"11\":[0,255,0,0,85,0,255,0,170,0,0,255],\"16\":[0,255,0,0,128,0,0,255]}}";
}

std::string NativeWledCore::presetsJson() const {
  if (_configRoot.empty()) return "{\"0\":{}}";
  ensurePresetsFile();
  std::ifstream file(_configRoot / "presets.json");
  if (!file) return "{\"0\":{}}";
  std::ostringstream contents;
  contents << file.rdbuf();
  return contents.str();
}

NativeCoreSnapshot NativeWledCore::snapshot(uint64_t nowMs) const {
  std::lock_guard<std::mutex> lock(_mutex);
  NativeCoreSnapshot snapshot;
  snapshot.state = _state;
  snapshot.effects = effectNames();
  snapshot.effectData.reserve(effectNames().size());
  for (const std::string &name : effectNames()) snapshot.effectData.push_back(name + "@!,!;!,!,!;!;01");
  snapshot.palettes = paletteNames();
  snapshot.uptimeSeconds = (nowMs - _startedMs) / 1000;
  return snapshot;
}

const std::filesystem::path &NativeWledCore::configRoot() const {
  return _configRoot;
}
